#[no_mangle]
pub fn rust_main(hart_id: usize) -> ! {
    #[cfg(feature = "smp")]
    use crate::arch::hart::start_other_harts;
    use core::sync::atomic::Ordering;

    use arch::{
        bootstrap_init,
        drivers::pci,
        timer::ls7a_rtc_init,
        trap::{
            self,
            timer::{enable_timer_interrupt, set_next_trigger},
            TrapContext,
        },
    };
    #[cfg(feature = "la2000")]
    use net::init_la2000_net;
    use task::run_tasks;
    if IS_BOOT
        .compare_exchange(true, false, Ordering::SeqCst, Ordering::SeqCst)
        .is_ok()
    {
        use crate::task::add_initproc;

        clear_bss();
        logging::init();
        bootstrap_init();
        mm::init();
        #[cfg(feature = "virt")]
        pci::init();
        trap::init();
        #[cfg(feature = "virt")]
        ls7a_rtc_init();
        println!("[kernel] boot hart {}", hart_id);
        #[cfg(feature = "smp")]
        start_other_harts(hart_id);
        #[cfg(feature = "la2000")]
        init_la2000_net();
        enable_timer_interrupt();
        set_next_trigger();
        add_initproc(hart_id);
        loader::list_apps();
        run_tasks(hart_id);
    } else {
        use crate::task::{other_initproc, other_run_tasks};
        bootstrap_init();
        mm::kernel_init();
        trap::init();
        enable_timer_interrupt();
        set_next_trigger();
        // other_initproc(hart_id);
        other_run_tasks(hart_id);
    }
    panic!("shutdown machine");
    // shutdown();
}

