/// 动态链接器候选路径：测例盘 musl/glibc 布局与 ELF `.interp` 字面路径常不一致。
fn interpreter_candidates(interp: &str, exe_path: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut push = |s: &str| {
        let s = s.to_string();
        if !out.contains(&s) {
            out.push(s);
        }
    };

    // LoongArch glibc ld.so 优先（测例盘布局与 .interp 字面路径常不一致）
    #[cfg(target_arch = "loongarch64")]
    if interp.contains("ld-linux") {
        push("/glibc/lib/ld-linux-loongarch-lp64d.so.1");
        push("/lib/ld-linux-loongarch-lp64d.so.1");
    }

    push(interp);

    let basename = interp.rsplit('/').next().unwrap_or(interp);
    let exe_dir = exe_path.rsplit_once('/').map(|(d, _)| d).unwrap_or("");

    if !exe_dir.is_empty() {
        push(&format!("{}/lib/{}", exe_dir, basename));
    }

    if interp.starts_with("/lib/") {
        let tail = &interp["/lib/".len()..];
        #[cfg(target_arch = "loongarch64")]
        {
            push(&format!("/glibc/lib/{}", tail));
            push(&format!("/musl/lib/{}", tail));
        }
        #[cfg(not(target_arch = "loongarch64"))]
        {
            push(&format!("/musl/lib/{}", tail));
            push(&format!("/glibc/lib/{}", tail));
        }
    }

    if interp.contains("ld-musl") {
        if !exe_dir.is_empty() {
            push(&format!("{}/libc.so", exe_dir));
            push(&format!("{}/lib/libc.so", exe_dir));
        }
        push("/musl/lib/libc.so");
        push(&format!("/musl/lib/{}", basename));
    }

    if interp.contains("ld-linux") {
        #[cfg(target_arch = "loongarch64")]
        {
            push("/glibc/lib/ld-linux-loongarch-lp64d.so.1");
            push("/lib/ld-linux-loongarch-lp64d.so.1");
        }
        if !exe_dir.is_empty() {
            push(&format!("{}/libc.so.6", exe_dir));
            push(&format!("{}/lib/libc.so.6", exe_dir));
        }
        push("/glibc/libc.so.6");
        push("/glibc/lib/libc.so.6");
        #[cfg(target_arch = "riscv64")]
        push("/glibc/lib/ld-linux-riscv64-lp64d.so.1");
        push(&format!("/glibc/lib/{}", basename));
    }

    out
}

