// helper
#[allow(unused)]
fn vec_to_u64(vec: &[u8]) -> Option<u64> {
    if vec.len() > 8 {
        return None;
    }

    let mut result = 0u64;
    for (i, &byte) in vec.iter().enumerate() {
        result |= (byte as u64) << (8 * i);
    }
    Some(result)
}

