/// Kernel futex
pub struct FutexQ {
    /// The `val` of the futex
    /// the task in the queue waiting for the same futex may have different `val`
    pub key: FutexKey,
    /// the task which is waiting for the futex
    pub task: Weak<Task>,
    /// the bitset of the futex
    pub bitset: u32,
}

impl FutexQ {
    /// Create a new futex queue
    pub fn new(key: FutexKey, task: Arc<Task>, bitset: u32) -> Self {
        Self {
            key,
            task: Arc::downgrade(&task),
            bitset,
        }
    }
    /// check if the futex queues matches the key
    pub fn match_key(&self, key: &FutexKey) -> bool {
        self.key == *key
    }
}

/// Remove `tid` from the bucket; drop entries whose task has already exited.
fn remove_futex_waiter(bucket: &mut VecDeque<FutexQ>, tid: usize) {
    bucket.retain(|futex_q| {
        futex_q
            .task
            .upgrade()
            .map(|task| task.tid() != tid)
            .unwrap_or(false)
    });
}

