impl IeGuard {
    /// Construct an IeGuard
    pub fn new() -> Self {
        Self({
            let mut crmd = CrMd::read();
            let ie_before = crmd.is_interrupt_enabled();
            crmd.set_ie(false);
            crmd.write();
            ie_before
        })
    }
