//! POSIX record lock (fcntl F_SETLK/F_GETLK/F_SETLKW) implementation.
//!
//! Locks are stored per-inode in a global table, keyed by the inode's Arc pointer.
//! Each lock records its type (read/write), byte range, and owning PID.
//!
//! Rules:
//!   - Read locks (F_RDLCK) are shared — multiple processes can hold read locks
//!     on the same range.
//!   - Write locks (F_WRLCK) are exclusive — no other lock (read or write) from
//!     a different process may overlap.
//!   - A process's new lock automatically replaces any overlapping locks it
//!     already holds on the same inode.
//!   - F_UNLCK removes the calling process's locks in the given range.

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use alloc::vec::Vec;
use lazy_static::lazy_static;
use spin::Mutex;

use super::inode::InodeOp;
use super::uapi::{Flock, F_RDLCK, F_UNLCK, F_WRLCK};
use crate::syscall::errno::Errno;
use crate::task::current_task;
use crate::signal::{Sig, SigInfo};

/// A single POSIX record lock entry (normalised to absolute byte offsets).
#[derive(Debug, Clone)]
struct FileLock {
    /// F_RDLCK (0) or F_WRLCK (1).  F_UNLCK entries are never stored.
    l_type: i16,
    /// Absolute start offset (bytes from start of file, ≥0).
    l_start: i64,
    /// Absolute end offset (exclusive).  `i64::MAX` means "to end of file".
    l_end: i64,
    /// PID of the owning process.
    l_pid: u32,
}

/// Key that uniquely identifies an inode in the global lock table.
type InodeKey = usize;

lazy_static! {
    /// Global record-lock table: inode → list of active locks.
    static ref INODE_LOCKS: Mutex<BTreeMap<InodeKey, Vec<FileLock>>> =
        Mutex::new(BTreeMap::new());

    /// Waiters blocked on F_SETLKW: inode → list of TIDs waiting.
    static ref WAITERS: Mutex<BTreeMap<InodeKey, Vec<usize>>> =
        Mutex::new(BTreeMap::new());

    /// Deadlock-detection graph: waiter TID → set of holder PIDs it is waiting for.
    static ref BLOCKED_ON: Mutex<BTreeMap<usize, Vec<u32>>> =
        Mutex::new(BTreeMap::new());

    /// File-lease table: inode → (lease_type, holder_pid).
    /// lease_type = F_RDLCK or F_WRLCK.  F_UNLCK means no lease.
    static ref LEASES: Mutex<BTreeMap<InodeKey, (i16, u32)>> =
        Mutex::new(BTreeMap::new());

