// Todo:
// 管理页缓存, 注意页缓存只存储文件的数据, 不存储元数据
pub struct AddressSpace {
    // Todo: linux使用的是`xarray`, 这里先用`BTreeMap`代替
    // 页缓存, key是页在文件中的页偏移(Page->index), value是页缓存
    // Todo: 这个要换成读写锁
    pub i_pages: BTreeMap<usize, Arc<Page>>, // 文件对应的页缓存
}

impl AddressSpace {
    pub fn new() -> Self {
        Self {
            i_pages: BTreeMap::new(),
        }
    }
    /// offset是页在文件中的页偏移(以PAGE_SIZE为单位)
    /// 如果未命中, 不会创建新的页缓存
    pub fn get_page_cache(self: &Self, page_index: usize) -> Option<Arc<Page>> {
        // 看i_pages中是否有对应的页缓存
        if let Some(page) = self.i_pages.get(&page_index) {
            return Some(page.clone());
        } else {
            None
        }
    }
    pub fn remove_page_cache(self: &mut Self, page_offset: usize) {
        // 删除页缓存
        self.i_pages.remove(&page_offset).or_else(|| {
            log::error!("remove_page_cache: page_offset {} not found", page_offset);
            None
        });
    }
    pub fn new_page_cache(
        self: &mut Self,
        page_index: usize,
        fs_block_id: usize,
        block_device: Arc<dyn BlockDevice>,
        inode: Weak<dyn InodeOp>,
    ) -> Arc<Page> {
        // 注意有可能稀疏文件
        if fs_block_id >= MAX_FS_BLOCK_ID {
            log::warn!("new_page_cache: fs_block_id is usize::MAX, sparse file");
        }
        let page = Arc::new(Page::new_filebe(fs_block_id, block_device, inode));
        self.i_pages.insert(page_index, page.clone());
        page
    }
    pub fn new_inline_page_cache(
        self: &mut Self,
        page_index: usize,
        inode: Weak<dyn InodeOp>,
        inline_data: &[u8],
    ) -> Arc<Page> {
        // inline data目前最大是60字节, 应该是第一页
        debug_assert!(page_index == 0);
        let page = Page::new_inline(inode, inline_data);
        self.i_pages.insert(page_index, page.clone());
        page
    }
    // Page有Drop trait, 会写回到磁盘
    pub fn clear(self: &mut Self) {
        self.i_pages.clear();
    }
    pub fn len(self: &Self) -> usize {
        self.i_pages.len()
    }
}

use std::env;
use std::fs::{read_dir, File};
use std::io::{Result, Write};

fn main() {
    let target_path = env::var("USER_TARGET_PATH")
        .unwrap_or_else(|_| "../user/target/loongarch64-unknown-none/release/".to_string());
    println!("cargo:rerun-if-changed=../user/src/");
    println!("cargo:rerun-if-changed=../user/src/ltp_patches/");
    println!("cargo:rerun-if-changed={}", target_path);
    insert_app_data(&target_path).unwrap();
}

fn insert_app_data(target_path: &str) -> Result<()> {
    let mut f = File::create("src/link_app.S").unwrap();
    // 收集 ../user/src/bin 下的应用 (Rust 编译出来的 ELF)
    let mut apps: Vec<(String, String)> = read_dir("../user/src/bin")
        .unwrap()
        .into_iter()
        .filter(|dir_entry| {
            let entry = dir_entry.as_ref().unwrap();
            entry.file_type().unwrap().is_file()
                && entry
                    .file_name()
                    .to_str()
                    .is_some_and(|name| name.ends_with(".rs"))
        })
        .map(|dir_entry| {
            let mut name_with_ext = dir_entry.unwrap().file_name().into_string().unwrap();
            name_with_ext.drain(name_with_ext.find('.').unwrap()..name_with_ext.len());
            let name = name_with_ext.clone();
            let path = format!("{}{}", target_path, name); // 对应 release 下的可执行文件
            (name, path)
        })
        .collect();
    let arch = if target_path.contains("loongarch64") {
        "la"
    } else {
        "rv"
    };
    let img_path = format!("../img/{}/", arch);
    // 收集 ./img/bin 下的应用 (直接是ELF可执行文件)
    let mut img_apps: Vec<(String, String)> = read_dir(img_path)
        .unwrap()
        .into_iter()
        .filter(|dir_entry| dir_entry.as_ref().unwrap().file_type().unwrap().is_file())
        .map(|dir_entry| {
            let name = dir_entry.unwrap().file_name().into_string().unwrap();
            let path = format!("../img/{}/{}", arch, name);
            (name, path)
        })
        .collect();
    // 合并
    apps.append(&mut img_apps);

    // 按名字排序，保证顺序稳定
    apps.sort_by(|a, b| a.0.cmp(&b.0));

    // 写 _num_app
    writeln!(
        f,
        r#"
    .align 3
    .section .data
    .global _num_app
_num_app:
    .quad {}"#,
        apps.len()
    )?;

    for i in 0..apps.len() {
        writeln!(f, r#"    .quad app_{}_start"#, i)?;
    }
    writeln!(f, r#"    .quad app_{}_end"#, apps.len() - 1)?;

    // 写 _app_names
    writeln!(
        f,
        r#"
    .global _app_names
_app_names:"#
    )?;
    for (name, _) in apps.iter() {
        writeln!(f, r#"    .string "{}""#, name)?;
    }

    // 写每个 app 的数据段
    for (idx, (name, path)) in apps.iter().enumerate() {
        println!("app_{}: {} ({})", idx, name, path);
        writeln!(
            f,
            r#"
    .section .data
    .global app_{0}_start
    .global app_{0}_end
    .align 3
app_{0}_start:
    .incbin "{1}"
app_{0}_end:"#,
            idx, path
        )?;
    }
    Ok(())
}

